+                } else {
+                    x[block_root] = x[block_root].max(x[pred_root] + sep);
+                }
+            }
+            let next = align[w];
+            if next == w {
+                break; // End of block chain (self-referencing terminal).
+            }
+            w = next;
+        }
+    }
