+    // Propagate block root coordinates to all block members.
+    for v in 0..node_count {
+        x[v] = x[root[v]];
+    }
+
+    // Apply class shifts.
+    for v in 0..node_count {
+        if root[v] == v {
+            let s = shift[sink[v]];
+            if s < f32::INFINITY {
